module sram_cell (  
    input wire [7:0] data_in,  
    input wire we,  
    input wire re,  
    output reg [7:0] data_out  
);  
    reg [7:0] mem;  

    always @(*) begin  
        if (we) begin  
            mem <= data_in;  
        end  
        if (re) begin  
            data_out <= mem;  
        end  
    end  
endmodule
